SHAR_EOF
  ${echo} 'x -gunzipping file .xemacs/ansi-color.el' &&
  gzip -d < ${lock_dir}/gzi > '.xemacs/ansi-color.el' &&
  (set 20 09 03 24 17 27 30 '.xemacs/ansi-color.el'; eval "$shar_touch") &&
  chmod 0644 '.xemacs/ansi-color.el'
if test $? -ne 0
then ${echo} 'restore of ''.xemacs/ansi-color.el'' failed'
fi
  if ${md5check}
  then (
       ${MD5SUM} -c >/dev/null 2>&1 || ${echo} '.xemacs/ansi-color.el': 'MD5 check failed'
       ) << SHAR_EOF
f95084194ec326330475daadc7b3208c  .xemacs/ansi-color.el
SHAR_EOF
  else
test `LC_ALL=C wc -c < '.xemacs/ansi-color.el'` -ne 25104 && \
  ${echo} 'restoration warning:  size of ''.xemacs/ansi-color.el'' is not 25104'
  fi
fi
# ============= .xemacs/ansys-mode.el ==============
if test ! -d '.xemacs'; then
  mkdir '.xemacs'
if test $? -eq 0
then ${echo} 'x - created directory `''.xemacs'\''.'
else ${echo} 'x - failed to create directory `''.xemacs'\''.'
  exit 1
fi
fi
if test -f '.xemacs/ansys-mode.el' && test "$first_param" != -c; then
  ${echo} 'x -SKIPPING ''.xemacs/ansys-mode.el'' (file already exists)'
else
${echo} 'x - extracting ''.xemacs/ansys-mode.el'' (gzipped)'
  sed 's/^X//' << 'SHAR_EOF' | uudecode &&
