SHAR_EOF
  ${echo} 'x -gunzipping file .xemacs/cmake-mode.el' &&
  gzip -d < ${lock_dir}/gzi > '.xemacs/cmake-mode.el' &&
  (set 20 09 03 24 17 27 31 '.xemacs/cmake-mode.el'; eval "$shar_touch") &&
  chmod 0644 '.xemacs/cmake-mode.el'
if test $? -ne 0
then ${echo} 'restore of ''.xemacs/cmake-mode.el'' failed'
fi
  if ${md5check}
  then (
       ${MD5SUM} -c >/dev/null 2>&1 || ${echo} '.xemacs/cmake-mode.el': 'MD5 check failed'
       ) << SHAR_EOF
1bd805ed0d4f5940f54becbe82dfc0f2  .xemacs/cmake-mode.el
SHAR_EOF
  else
test `LC_ALL=C wc -c < '.xemacs/cmake-mode.el'` -ne 9356 && \
  ${echo} 'restoration warning:  size of ''.xemacs/cmake-mode.el'' is not 9356'
  fi
fi
# ============= .xemacs/color-theme.el ==============
if test -f '.xemacs/color-theme.el' && test "$first_param" != -c; then
  ${echo} 'x -SKIPPING ''.xemacs/color-theme.el'' (file already exists)'
else
${echo} 'x - extracting ''.xemacs/color-theme.el'' (gzipped)'
