SHAR_EOF
  ${echo} 'x -gunzipping file .xemacs/color-theme.el' &&
  gzip -d < ${lock_dir}/gzi > '.xemacs/color-theme.el' &&
  (set 20 09 03 24 17 27 31 '.xemacs/color-theme.el'; eval "$shar_touch") &&
  chmod 0644 '.xemacs/color-theme.el'
if test $? -ne 0
then ${echo} 'restore of ''.xemacs/color-theme.el'' failed'
fi
  if ${md5check}
  then (
       ${MD5SUM} -c >/dev/null 2>&1 || ${echo} '.xemacs/color-theme.el': 'MD5 check failed'
       ) << SHAR_EOF
ee252d5e80096420b27f573f85cff746  .xemacs/color-theme.el
SHAR_EOF
  else
test `LC_ALL=C wc -c < '.xemacs/color-theme.el'` -ne 880060 && \
  ${echo} 'restoration warning:  size of ''.xemacs/color-theme.el'' is not 880060'
  fi
fi
# ============= .xemacs/cua-base.el ==============
if test -f '.xemacs/cua-base.el' && test "$first_param" != -c; then
  ${echo} 'x -SKIPPING ''.xemacs/cua-base.el'' (file already exists)'
else
${echo} 'x - extracting ''.xemacs/cua-base.el'' (gzipped)'
