SHAR_EOF
  ${echo} 'x -gunzipping file .xemacs/init.el' &&
  gzip -d < ${lock_dir}/gzi > '.xemacs/init.el' &&
  (set 20 09 08 03 15 58 12 '.xemacs/init.el'; eval "$shar_touch") &&
  chmod 0644 '.xemacs/init.el'
if test $? -ne 0
then ${echo} 'restore of ''.xemacs/init.el'' failed'
fi
  if ${md5check}
  then (
       ${MD5SUM} -c >/dev/null 2>&1 || ${echo} '.xemacs/init.el': 'MD5 check failed'
       ) << SHAR_EOF
61b1c5fccfe9bc7af032c3528cafd16d  .xemacs/init.el
SHAR_EOF
  else
test `LC_ALL=C wc -c < '.xemacs/init.el'` -ne 15509 && \
  ${echo} 'restoration warning:  size of ''.xemacs/init.el'' is not 15509'
  fi
fi
