SHAR_EOF
  ${echo} 'x -gunzipping file .xemacs/matlab.el' &&
  gzip -d < ${lock_dir}/gzi > '.xemacs/matlab.el' &&
  (set 20 09 03 24 17 27 31 '.xemacs/matlab.el'; eval "$shar_touch") &&
  chmod 0644 '.xemacs/matlab.el'
if test $? -ne 0
then ${echo} 'restore of ''.xemacs/matlab.el'' failed'
fi
  if ${md5check}
  then (
       ${MD5SUM} -c >/dev/null 2>&1 || ${echo} '.xemacs/matlab.el': 'MD5 check failed'
       ) << SHAR_EOF
8f06a95207af1f72dd8e69fb1e0b485f  .xemacs/matlab.el
SHAR_EOF
  else
test `LC_ALL=C wc -c < '.xemacs/matlab.el'` -ne 209572 && \
  ${echo} 'restoration warning:  size of ''.xemacs/matlab.el'' is not 209572'
  fi
fi
