SHAR_EOF
  ${echo} 'x -gunzipping file .xemacs/gnuplot.elc' &&
  gzip -d < ${lock_dir}/gzi > '.xemacs/gnuplot.elc' &&
  (set 20 09 03 24 17 27 31 '.xemacs/gnuplot.elc'; eval "$shar_touch") &&
  chmod 0644 '.xemacs/gnuplot.elc'
if test $? -ne 0
then ${echo} 'restore of ''.xemacs/gnuplot.elc'' failed'
fi
  if ${md5check}
  then (
       ${MD5SUM} -c >/dev/null 2>&1 || ${echo} '.xemacs/gnuplot.elc': 'MD5 check failed'
       ) << SHAR_EOF
c270c5707a2a1e309062cf6441cdf8fe  .xemacs/gnuplot.elc
SHAR_EOF
  else
test `LC_ALL=C wc -c < '.xemacs/gnuplot.elc'` -ne 73987 && \
  ${echo} 'restoration warning:  size of ''.xemacs/gnuplot.elc'' is not 73987'
  fi
fi
# ============= .xemacs/gnuplot-gui.elc ==============
if test -f '.xemacs/gnuplot-gui.elc' && test "$first_param" != -c; then
  ${echo} 'x -SKIPPING ''.xemacs/gnuplot-gui.elc'' (file already exists)'
else
${echo} 'x - extracting ''.xemacs/gnuplot-gui.elc'' (gzipped)'
  sed 's/^X//' << 'SHAR_EOF' | uudecode &&
