SHAR_EOF
  ${echo} 'x -gunzipping file .xemacs/gnuplot-gui.elc' &&
  gzip -d < ${lock_dir}/gzi > '.xemacs/gnuplot-gui.elc' &&
  (set 20 09 03 24 17 27 30 '.xemacs/gnuplot-gui.elc'; eval "$shar_touch") &&
  chmod 0644 '.xemacs/gnuplot-gui.elc'
if test $? -ne 0
then ${echo} 'restore of ''.xemacs/gnuplot-gui.elc'' failed'
fi
  if ${md5check}
  then (
       ${MD5SUM} -c >/dev/null 2>&1 || ${echo} '.xemacs/gnuplot-gui.elc': 'MD5 check failed'
       ) << SHAR_EOF
6bfe0f80bff7d7ddd58b76843773a337  .xemacs/gnuplot-gui.elc
SHAR_EOF
  else
test `LC_ALL=C wc -c < '.xemacs/gnuplot-gui.elc'` -ne 52884 && \
  ${echo} 'restoration warning:  size of ''.xemacs/gnuplot-gui.elc'' is not 52884'
  fi
fi
