SHAR_EOF
  ${echo} 'x -gunzipping file .xemacs/info-look.elc' &&
  gzip -d < ${lock_dir}/gzi > '.xemacs/info-look.elc' &&
  (set 20 09 03 24 17 27 31 '.xemacs/info-look.elc'; eval "$shar_touch") &&
  chmod 0644 '.xemacs/info-look.elc'
if test $? -ne 0
then ${echo} 'restore of ''.xemacs/info-look.elc'' failed'
fi
  if ${md5check}
  then (
       ${MD5SUM} -c >/dev/null 2>&1 || ${echo} '.xemacs/info-look.elc': 'MD5 check failed'
       ) << SHAR_EOF
be98188df32c77824954d50bb6fa20f7  .xemacs/info-look.elc
SHAR_EOF
  else
test `LC_ALL=C wc -c < '.xemacs/info-look.elc'` -ne 18811 && \
  ${echo} 'restoration warning:  size of ''.xemacs/info-look.elc'' is not 18811'
  fi
fi
